// Minimal Notyf shim implementing the subset of API used by the project.
// Methods: constructor(options), success(message), error(message), open({type,message})
(function(global){
    function Notyf(opts){
        this.duration = (opts && opts.duration) || 3500;
        this.position = (opts && opts.position) || { x: 'right', y: 'top' };
        this.container = null;
        this._ensureContainer();
    }

    Notyf.prototype._ensureContainer = function(){
        if (this.container) return this.container;
        const c = document.createElement('div');
        c.id = 'notyf-container';
        c.style.position = 'fixed';
        c.style.top = '1rem';
        c.style.right = '1rem';
        c.style.zIndex = 99999;
        // Append to body if available, otherwise fall back to documentElement.
        // If DOM isn't ready yet, listen for DOMContentLoaded and append then.
        var parent = document.body || document.getElementsByTagName('body')[0] || document.documentElement;
        try {
            parent.appendChild(c);
        } catch (e) {
            try {
                document.addEventListener('DOMContentLoaded', function() {
                    try { (document.body || document.getElementsByTagName('body')[0] || document.documentElement).appendChild(c); } catch (e2) { /* ignore */ }
                });
            } catch (e2) { /* ignore */ }
        }
        this.container = c;
        return c;
    };

    Notyf.prototype._show = function(message, cssClass){
        const c = this._ensureContainer();
        const el = document.createElement('div');
        el.className = 'notyf ' + cssClass;
        el.textContent = message || '';
        c.appendChild(el);
        requestAnimationFrame(()=>{ el.style.opacity = '1'; el.style.transform = 'none'; });
        setTimeout(()=>{ try{ el.style.opacity = '0'; el.style.transform = 'translateY(-6px)'; setTimeout(()=>{ try{ c.removeChild(el) }catch(e){} },200) }catch(e){} }, this.duration);
    };

    Notyf.prototype.success = function(msg){ this._show(msg, 'notyf--success'); };
    Notyf.prototype.error = function(msg){ this._show(msg, 'notyf--error'); };
    Notyf.prototype.open = function(o){ if (o && o.type==='info') this._show(o.message, 'notyf--info'); else if (o && o.type==='warning') this._show(o.message, 'notyf--warning'); };

    global.Notyf = Notyf;
})(window);
